Use
TCPEndpointConnect or TCPEndpointListen:
struct
TCPEndpointListenMsg: public TCPEndpointBaseMsg
{
public:
IPAddress lAddress; // my address
Port lPort;
IPAddress fAddress; // the address sending data
Port fPort;
}
struct
TCPEndpointConnectMsg: public TCPEndpointBaseMsg
{
public:
IPAddress lAddress; // my address
Port lPort;
IPAddress fAddress; // the address sending data
Port fPort;
}
